Spring Physics

// Snappy, no bounce
transition={{ type: 'spring', stiffness: 400, damping: 30 }}
// Bouncy
transition={{ type: 'spring', stiffness: 200, damping: 10 }}
// Slow, heavy
transition={{ type: 'spring', stiffness: 80, damping: 20 }}

