Gesture Animations

<motion.div
whileHover={{ scale: 1.02, y: -4 }}
whileTap={{ scale: 0.98 }}
transition={{ type: 'spring', stiffness: 400, damping: 17 }}
className="cursor-pointer rounded-xl border p-6"
>
Card content
</motion.div>

