SVG Path Animation

<motion.path
d="M14 27 L21 34 L38 17"
fill="none" stroke="currentColor" strokeWidth="3"
initial={{ pathLength: 0 }}
animate={{ pathLength: 1 }}
transition={{ duration: 0.4, delay: 0.5 }}
/>

